    typealias SwiftType = [GrpcHeader]

    public static func write(_ value: [GrpcHeader], into buf: inout [UInt8]) {
        let len = Int32(value.count)
        writeInt(&buf, len)
        for item in value {
            FfiConverterTypeGrpcHeader.write(item, into: &buf)
        }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> [GrpcHeader] {
        let len: Int32 = try readInt(&buf)
        var seq = [GrpcHeader]()
        seq.reserveCapacity(Int(len))
        for _ in 0 ..< len {
            seq.append(try FfiConverterTypeGrpcHeader.read(from: &buf))
        }
        return seq
    }
